input.command:
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval "
var users = ['admin', 'root', 'administrator', 'mongo'];
var pass = 'admin123password';
users.forEach(function(u) {
  try {
    var r = db.getSiblingDB('admin').auth(u, pass);
    print('auth ' + u + ': ' + r);
  } catch(e) { print('fail ' + u + ': ' + e.message); }
});
" 2>&1

kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval "
db.getSiblingDB('admin').createUser({
  user: 'admin',
  pwd: 'admin123password',
  roles: [{role: 'root', db: 'admin'}]
});
print('user created');
" 2>&1

kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --host 127.0.0.1 --eval "
db.getSiblingDB('admin').createUser({
  user: 'admin',
  pwd: 'admin123password',
  roles: [{role: 'root', db: 'admin'}]
});
print('user created');
" 2>&1

